WHERE c.GEOCODE_YN = 'Y' AND j.USE_YN = 'Y' AND j.DEL_YN = 'N' AND c.LAT BETWEEN #{swLat} AND #{neLat} AND c.LNG BETWEEN #{swLng} AND #{neLng} AND ( j.CLOSE_DT IS NULL OR TRIM(j.CLOSE_DT) = '' OR TRIM(j.CLOSE_DT) IN ('상시채용', '채용시까지') OR TRIM(j.CLOSE_DT) NOT REGEXP '^[0-9]{4}[-.]?[0-9]{1,2}[-.]?[0-9]{1,2}$' OR ( CASE WHEN TRIM(j.CLOSE_DT) REGEXP '^[0-9]{8}$' THEN STR_TO_DATE(TRIM(j.CLOSE_DT), '%Y%m%d') ELSE STR_TO_DATE(REPLACE(TRIM(j.CLOSE_DT), '.', '-'), '%Y-%c-%e') END ) >= CURDATE() )
AND j.SOURCE_TYPE COLLATE utf8mb4_unicode_ci = '공공' COLLATE utf8mb4_unicode_ci
AND j.SOURCE_TYPE COLLATE utf8mb4_unicode_ci = '민간' COLLATE utf8mb4_unicode_ci
