#{code}

mapper.select:
SELECT j.WANTED_AUTH_NO AS wantedAuthNo, j.SOURCE AS source, j.SOURCE_TYPE AS sourceType, j.COMPANY AS company, j.TITLE AS title, j.JOBS_NM AS jobsNm, j.JOBS_CD AS jobsCd, j.EMP_TP_NM AS empTpNm, j.CAREER AS career, j.MIN_EDUBG AS minEdubg, j.SAL_AMT AS salAmt, j.SAL_TP_NM AS salTpNm, j.REGION AS region, j.CLOSE_DT AS closeDt, j.WANTED_INFO_URL AS wantedInfoUrl, j.BASIC_ADDR AS basicAddr, j.DETAIL_ADDR AS detailAddr, j.INFO_SVC AS infoSvc, j.JOB_CAREER_CD AS jobCareerCd, j.JOB_ACDMCR_CD AS jobAcdmcrCd, j.JOB_EMP_TP_CD AS jobEmpTpCd, j.JOB_AREA_CD AS jobAreaCd, j.JOBABA_CMMN_276_CD AS jobabaCmmn276Cd, j.JOBABA_CMMN_274_CD AS jobabaCmmn274Cd FROM v_job_posting j LEFT JOIN tb_empmn_map_coord c ON j.WANTED_AUTH_NO = c.WANTED_AUTH_NO WHERE j.USE_YN = 'Y' AND j.DEL_YN = 'N' AND j.BASIC_ADDR IS NOT NULL AND TRIM(j.BASIC_ADDR) != '' AND (c.WANTED_AUTH_NO IS NULL OR c.GEOCODE_YN = 'N')
AND j.SOURCE_TYPE COLLATE utf8mb4_unicode_ci = '공공' COLLATE utf8mb4_unicode_ci
AND j.SOURCE_TYPE COLLATE utf8mb4_unicode_ci = '민간' COLLATE utf8mb4_unicode_ci
AND (j.COMPANY LIKE CONCAT('%', #{keyword}, '%') ESCAPE '\\' OR j.TITLE LIKE CONCAT('%', #{keyword}, '%') ESCAPE '\\' OR j.JOBS_NM LIKE CONCAT('%', #{keyword}, '%') ESCAPE '\\')
AND EXISTS ( SELECT 1 FROM tb_jobcls_ncs_map m WHERE m.NCS_CD IN
#{code}
AND m.JOBABA_GRP_CD = 'CMMN_276' AND m.JOBABA_CD = j.JOBABA_CMMN_276_CD AND m.USE_YN = 'Y' )
AND (
FIND_IN_SET(#{code}, j.JOB_CAREER_CD)
)
AND (
FIND_IN_SET(#{code}, j.JOB_ACDMCR_CD)
)
AND (
FIND_IN_SET(#{code}, j.JOB_EMP_TP_CD)
)
AND (
FIND_IN_SET(#{code}, j.JOB_EMP_TP_CD)
)
AND (
FIND_IN_SET(#{code}, j.JOB_CAREER_CD)
)
AND j.JOB_ACDMCR_CD IN
#{code}
AND j.JOBABA_CMMN_274_CD IN
#{code}
ORDER BY j.REG_DT DESC LIMIT #{size} OFFSET #{offset}
